122→function resolvePlaceholders(
123→  segments: string[],
124→  skillName: string,
125→  home: string
126→): string {
127→  const appdata = process.env["APPDATA"] ?? path.join(home, "AppData", "Roaming");
128→  const resolved = segments.map((seg) =>
129→    seg
130→      .replace("{home}", home)
131→      .replace("{name}", skillName)
132→      .replace("{appdata}", appdata)
133→  );
134→  return path.join(...resolved);
