 39→describe("executeRevert", () => {
 40→  if (process.platform === "win32") return;
 41→
 42→  it("removes a symlink", async () => {
 43→    const home = makeTmpDir();
 44→    const sourceDir = makeTmpDir();
 45→    try {
 46→      const actions = planRevert(testManifest, ["claude-code"], home);
 47→      const target = actions[0]!.target;
 48→
 49→      // Create the symlink to remove (sourceDir must contain SKILL.md for ownership check)
 50→      writeFileSync(path.join(sourceDir, "SKILL.md"), "---");
 51→      mkdirSync(path.dirname(target), { recursive: true });
