  1→#!/usr/bin/env node
  2→
  3→import path from "node:path";
  4→import { parseArgs } from "node:util";
  5→import { AGENT_IDS } from "./types.ts";
  6→import type { AgentId, CliOptions } from "./types.ts";
  7→import { loadManifest } from "./config/manifest.ts";
  8→import { AGENT_REGISTRY } from "./config/agents.ts";
  9→import { resolveHome } from "./core/resolve.ts";
 10→import { detectInstalledAgents } from "./core/detect.ts";
 11→import { planDeploy, executeDeploy } from "./core/deploy.ts";
 12→import { planRevert, executeRevert } from "./core/revert.ts";
 13→import { UserError } from "./errors.ts";
 14→import type { ErrorCode } from "./errors.ts";
 15→import { logger, dryRunPrefix } from "./logger.ts";
 16→
 17→const USAGE = `
 18→inception-engine - Deploy AI agent skills
 19→
 20→Usage:
 21→  inception-engine <directory> [options]
 22→  inception-engine revert <directory> [options]
 23→
 24→Options:
 25→  --dry-run        Show what would be done without doing it
 26→  --agents <list>  Comma-separated list of agent IDs to target
 27→  --verbose        Show detailed output
 28→  --debug          Show full error stack traces
 29→  --help           Show this help message
 30→
 31→Supported agents:
 32→  ${AGENT_REGISTRY.map((a) => `${a.id} (${a.displayName})`).join(", ")}
 33→`.trim();
 34→
 35→function parseCLI(argv: string[]): CliOptions {
 36→  const args = argv.slice(2);
 37→
 38→  if (args.length === 0) {
 39→    return { command: "help", directory: "", dryRun: false, agents: null, verbose: false, debug: false };
 40→  }
 41→
 42→  let parsed: ReturnType<typeof parseArgs>;
 43→  try {
 44→    parsed = parseArgs({
 45→      args,
 46→      allowPositionals: true,
 47→      options: {
 48→        "dry-run": { type: "boolean", default: false },
 49→        "verbose": { type: "boolean", default: false },
 50→        "debug": { type: "boolean", default: false },
 51→        "help": { type: "boolean", default: false },
 52→        "agents": { type: "string" },
 53→      },
 54→    });
 55→  } catch (err) {
 56→    throw new UserError("INVALID_ARGS", (err as Error).message);
 57→  }
 58→
 59→  const { values, positionals } = parsed;
 60→
 61→  if (values.help) {
 62→    return { command: "help", directory: "", dryRun: false, agents: null, verbose: false, debug: false };
 63→  }
 64→
 65→  let command: "deploy" | "revert" = "deploy";
 66→  let pos = positionals;
 67→  if (pos[0] === "revert") {
 68→    command = "revert";
 69→    pos = pos.slice(1);
 70→  }
 71→
 72→  if (pos.length > 1) {
 73→    throw new UserError("INVALID_ARGS", `Unexpected argument: ${pos[1]}`);
 74→  }
 75→  const rawDir = pos[0];
 76→  if (!rawDir) {
 77→    throw new UserError("INVALID_ARGS", "Missing required <directory> argument");
 78→  }
 79→
 80→  let agents: AgentId[] | null = null;
 81→  if (typeof values.agents === "string") {
 82→    const ids = values.agents.split(",").map((s) => s.trim());
 83→    for (const id of ids) {
 84→      if (!AGENT_IDS.includes(id as AgentId)) {
 85→        throw new UserError("INVALID_ARGS", `Unknown agent: "${id}". Valid agents: ${AGENT_IDS.join(", ")}`);
 86→      }
 87→    }
 88→    agents = ids as AgentId[];
 89→  }
 90→
 91→  return {
 92→    command,
 93→    directory: path.resolve(rawDir),
 94→    dryRun: values["dry-run"] as boolean,
 95→    agents,
 96→    verbose: values.verbose as boolean,
 97→    debug: values.debug as boolean,
 98→  };
 99→}
100→
101→async function main(): Promise<number> {
102→  const options = parseCLI(process.argv);
103→
104→  if (options.command === "help") {
105→    console.log(USAGE);
106→    return 0;
107→  }
108→
109→  const manifest = await loadManifest(options.directory);
110→  const home = resolveHome();
111→
112→  let detectedAgents: AgentId[];
113→  if (options.agents) {
114→    detectedAgents = options.agents;
115→    if (options.verbose) {
116→      logger.info(`Using specified agents: ${detectedAgents.join(", ")}`);
117→    }
118→  } else {
119→    detectedAgents = await detectInstalledAgents(home);
120→    if (detectedAgents.length === 0) {
121→      logger.info("No supported AI agents detected on this system.");
122→      logger.info(`Install one of: ${AGENT_REGISTRY.map((a) => a.displayName).join(", ")}`);
123→      return 0;
124→    }
125→    if (options.verbose) {
126→      logger.info(`Detected agents: ${detectedAgents.join(", ")}`);
127→    }
128→  }
129→
130→  if (options.command === "deploy") {
131→    const actions = planDeploy(manifest, options.directory, detectedAgents, home);
132→    if (actions.length === 0) {
133→      logger.info("No skills to deploy for detected agents.");
134→      return 0;
135→    }
136→
137→    logger.info(`${dryRunPrefix(options.dryRun)}Deploying ${actions.length} skill(s):`);
138→    const { succeeded, failed } = await executeDeploy(actions, options.dryRun, options.verbose);
139→
140→    logger.info("");
141→    if (failed.length > 0) {
142→      logger.info(`${succeeded} succeeded, ${failed.length} failed`);
143→      return 1;
144→    } else {
145→      logger.info(`${succeeded} skill(s) deployed${options.dryRun ? " (dry-run)" : ""}`);
146→    }
147→  } else {
148→    const actions = planRevert(manifest, detectedAgents, home);
149→    if (actions.length === 0) {
150→      logger.info("No skills to revert for detected agents.");
151→      return 0;
152→    }
153→
154→    logger.info(`${dryRunPrefix(options.dryRun)}Reverting ${actions.length} skill(s):`);
155→    const { succeeded, skipped } = await executeRevert(actions, options.dryRun, options.verbose);
156→
157→    logger.info("");
158→    const parts = [`${succeeded} removed`];
159→    if (skipped > 0) parts.push(`${skipped} skipped`);
160→    logger.info(`${parts.join(", ")}${options.dryRun ? " (dry-run)" : ""}`);
161→  }
162→
163→  return 0;
164→}
165→
166→const USER_ERROR_EXIT: Record<ErrorCode, number> = {
167→  INVALID_ARGS: 2,
168→  MANIFEST_INVALID: 3,
169→  DEPLOY_FAILED: 1,
170→  RESOLVE_FAILED: 1,
171→};
172→
173→const debugMode = process.argv.includes("--debug");
174→
175→try {
176→  process.exit(await main());
177→} catch (err) {
178→  if (err instanceof UserError) {
179→    logger.error(`Error: ${err.message}`);
180→    if (debugMode) {
181→      logger.errorRaw(err);
182→    }
183→    process.exit(USER_ERROR_EXIT[err.code]);
184→  } else {
185→    logger.error("Unexpected error. Run with --debug for details.");
186→    if (debugMode) {
187→      logger.errorRaw(err);
188→    }
189→    process.exit(1);
190→  }
191→}
